const items = $input.all();
const results = [];
for (const item of items) {
  const campanha = item.json;
  const sessoes = Array.isArray(campanha.dados_sessoes) ? campanha.dados_sessoes : [];
  const amostraMensagens = sessoes.slice(0, 10).map(s => ({
    respondeu: s.respondeu,
    sentimento: s.sentimento,
    preview: JSON.stringify(s.mensagens || []).substring(0, 300)
  }));
  const prompt = `Analise os dados desta campanha de marketing e retorne um JSON com:\n- sentimento_positivo_pct: porcentagem de sentimentos positivos (0-100)\n- sentimento_neutro_pct: porcentagem de sentimentos neutros (0-100)\n- sentimento_negativo_pct: porcentagem de sentimentos negativos (0-100)\n- elementos_efetivos: array de strings com elementos que funcionaram bem\n- elementos_rejeitados: array de strings com elementos que foram mal recebidos\n- score_campanha: número de 0 a 10\n- aprendizados: array de strings com aprendizados e recomendações\n\nDados da campanha:\n- Nome: ${campanha.campanha_nome}\n- Total enviados: ${campanha.total_enviados}\n- Total responderam: ${campanha.total_responderam}\n- Taxa de resposta: ${campanha.taxa_resposta}%\n- Amostra de sessões: ${JSON.stringify(amostraMensagens)}\n\nRetorne APENAS o JSON, sem explicações.`;
  results.push({
    json: {
      ...campanha,
      prompt
    }
  });
}
return results;

const response = $input.first().json;
const content = response.content?.[0]?.text || '{}';
let parsed;
try { parsed = JSON.parse(content); } catch(e) { parsed = {erro: 'parse_failed', raw: content.substring(0,200)}; }
return [{json: {...$input.first().json, resultado: parsed}}];
